type CardProps = {
  title?: string;
  children: React.ReactNode;
} & React.HTMLAttributes<HTMLDivElement>;

function Card({ title = "Untitled", children, ...rest }: CardProps) {
  return (
    <div className="card" {...rest}>
      <h2>{title}</h2>
      {children}
    </div>
  );
}

<Card title="Hello" className="featured"><p>Hi</p></Card>;

function App() {
  const user = { name: "Ada" };
  return <div>{user}</div>;
}
